<?php
namespace App\Services;
class ReviewService{public function __construct(private \App\Contracts\Repositories\ReviewRepositoryInterface $reviews){} public function create(array $d){$review=$this->reviews->create($d);$this->recalculate($review->culinary_place_id);return $review;} public function update(int $id,array $d){$review=$this->reviews->update($id,$d);$this->recalculate($review->culinary_place_id);return $review;} public function delete(int $id){$review=$this->reviews->find($id);$place=$review->culinary_place_id;$deleted=$this->reviews->delete($id);$this->recalculate($place);return $deleted;} private function recalculate($placeId){$avg=\App\Models\Review::where('culinary_place_id',$placeId)->where('status','published')->avg('rating')??0;$total=\App\Models\Review::where('culinary_place_id',$placeId)->where('status','published')->count();\App\Models\CulinaryPlace::whereKey($placeId)->update(['rating_average'=>$avg,'rating_total'=>$total]);}}
